if err != nil {
return err
}
// create a new record instance
// or fetch existing, eg. app.Dao().FindFirstRecordByData(collection, "yourField", "yourValue")
record := models.NewRecord(collection)
record.SetDataValue("yourField1", "yourValue1")
record.SetDataValue("yourField2", "yourValue2")
// upsert
if err := app.Dao().SaveRecord(record); err != nil {
